  3→const CONFIDENCE_TIERS = {
  4→    high:   { threshold: 0.60, maxResults: 5, label: 'high' },
  5→    medium: { threshold: 0.48, maxResults: 3, label: 'medium' },
  6→    low:    { threshold: 0.38, maxResults: 2, label: 'low' },
  7→};
  8→
  9→let _dynamicFloorCache = { value: null, ts: 0 };
 10→const DYNAMIC_FLOOR_TTL_MS = 5 * 60 * 1000; // 5 minutes
 11→
 12→async function getDynamicFloor() {
 13→    if (_dynamicFloorCache.value !== null && Date.now() - _dynamicFloorCache.ts < DYNAMIC_FLOOR_TTL_MS) {
 14→        return _dynamicFloorCache.value;
 15→    }
 16→
 17→    const { count, error } = await supabase
 18→        .from('journals')
 19→        .select('id', { count: 'exact', head: true })
 20→        .eq('privacy', 'public')
 21→        .not('embeddings', 'is', null);
 22→
 23→    if (error) {
 24→        console.error('getDynamicFloor count error:', error.message);
 25→        return _dynamicFloorCache.value ?? 0.30;
 26→    }
 27→
 28→    let floor;
 29→    if (count < 500)  floor = 0.35;
 30→    else if (count < 2000) floor = 0.40;
 31→    else floor = 0.45;
 32→
 33→    _dynamicFloorCache = { value: floor, ts: Date.now() };
 34→    return floor;
 35→}
 36→
 37→function getConfidenceTier(topSimilarity) {
 38→    if (topSimilarity >= CONFIDENCE_TIERS.high.threshold)   return CONFIDENCE_TIERS.high;
 39→    if (topSimilarity >= CONFIDENCE_TIERS.medium.threshold) return CONFIDENCE_TIERS.medium;
 40→    if (topSimilarity >= CONFIDENCE_TIERS.low.threshold)    return CONFIDENCE_TIERS.low;
 41→    return null;
 42→}
 43→
 44→export async function getRelatedPostsService(journalId) {
 45→    const dynamicFloor = await getDynamicFloor();
 46→
 47→    // First attempt with dynamic floor
 48→    let { data, error } = await supabase.rpc('find_related_posts', {
 49→        source_post_id: journalId,
 50→        match_count: 8,
 51→        similarity_floor: dynamicFloor,
 52→        recency_days: 365,
 53→    });
 54→
 55→    if (error) {
 56→        throw { status: 500, error: 'Failed to find related posts: ' + error.message };
 57→    }
 58→
 59→    // Fallback: if < 2 results, try with a lower floor
 60→    if (!data || data.length < 2) {
 61→        const lowerFloor = Math.max(dynamicFloor - 0.03, 0.30);
 62→        if (lowerFloor < dynamicFloor) {
 63→            const fallback = await supabase.rpc('find_related_posts', {
 64→                source_post_id: journalId,
 65→                match_count: 8,
 66→                similarity_floor: lowerFloor,
 67→                recency_days: 365,
 68→            });
 69→            if (!fallback.error && fallback.data && fallback.data.length >= 2) {
 70→                data = fallback.data;
 71→            }
 72→        }
 73→    }
 74→
 75→    // Never show fewer than 2 results
 76→    if (!data || data.length < 2) {
 77→        return { posts: [], confidence: 'none', topSimilarity: 0 };
 78→    }
 79→
 80→    const topSimilarity = data[0]?.semantic_similarity || 0;
 81→    const tier = getConfidenceTier(topSimilarity);
 82→
 83→    if (!tier) {
 84→        return { posts: [], confidence: 'none', topSimilarity };
 85→    }
 86→
 87→    // Cap results by confidence tier
 88→    const cappedPosts = data.slice(0, tier.maxResults);
 89→
 90→    // Ensure we still have at least 2 after capping
 91→    if (cappedPosts.length < 2) {
 92→        return { posts: [], confidence: 'none', topSimilarity };
 93→    }
 94→
 95→    return {
 96→        posts: cappedPosts,
 97→        confidence: tier.label,
 98→        topSimilarity,
 99→    };
100→}
