271→export const updateStoryService = async (storyId, userId, updates, coverFile) => {
272→    if (!storyId || !userId) {
273→        throw { status: 400, error: 'storyId and userId are required' };
274→    }
275→
276→    // Verify ownership (also grab title + description for embedding check)
277→    const { data: existing, error: fetchError } = await supabase
278→        .from('stories')
279→        .select('author_id, title, description')
280→        .eq('id', storyId)
281→        .single();
282→
283→    if (fetchError || !existing) {
284→        throw { status: 404, error: 'story not found' };
285→    }
286→    if (existing.author_id !== userId) {
287→        throw { status: 403, error: 'not authorized to update this story' };
288→    }
289→
290→    const updateData = {};
291→    if (updates.title !== undefined) {
292→        if (!updates.title || updates.title.trim().length === 0) {
293→            throw { status: 400, error: 'title cannot be empty' };
294→        }
295→        updateData.title = updates.title.trim();
296→    }
297→    if (updates.description !== undefined) {
298→        updateData.description = (updates.description || '').trim();
299→    }
300→    if (updates.status !== undefined && ['ongoing', 'completed', 'hiatus'].includes(updates.status)) {
301→        updateData.status = updates.status;
302→    }
303→    if (updates.privacy !== undefined && ['public', 'private'].includes(updates.privacy)) {
304→        updateData.privacy = updates.privacy;
305→    }
306→    if (updates.tags !== undefined) {
307→        let parsedTags = [];
308→        try {
309→            parsedTags = typeof updates.tags === 'string' ? JSON.parse(updates.tags) : updates.tags;
310→            if (!Array.isArray(parsedTags)) parsedTags = [];
311→            parsedTags = parsedTags.slice(0, 10).map(t => String(t).trim()).filter(Boolean);
312→        } catch {
313→            parsedTags = [];
314→        }
315→        updateData.tags = parsedTags;
316→    }
317→
318→    if (coverFile) {
319→        updateData.cover_url = await imageUploader(coverFile, userId, 'story-covers');
320→    }
321→
322→    if (Object.keys(updateData).length === 0) {
323→        throw { status: 400, error: 'no valid fields to update' };
324→    }
325→
326→    // Regenerate embedding if title or description changed
327→    if (updateData.title !== undefined || updateData.description !== undefined) {
328→        const resolvedTitle = updateData.title ?? existing.title;
329→        const resolvedDesc = updateData.description ?? (existing.description || '');
330→        const embedding = await GenerateEmbeddings(resolvedTitle, resolvedDesc);
331→        if (embedding && Array.isArray(embedding) && embedding.length > 0) {
332→            updateData.embedding = embedding;
333→        }
334→    }
335→
336→    const { data, error } = await supabase
337→        .from('stories')
338→        .update(updateData)
339→        .eq('id', storyId)
340→        .select(STORY_SELECT_COLUMNS)
341→        .single();
342→
343→    if (error) {
344→        console.error('supabase error updating story:', error.message);
345→        throw { status: 500, error: 'failed to update story' };
346→    }
347→
348→    return decorateStoryMedia(stripEmbedding(data), 'detail');
349→};
