223→export const uploadJournalContentService = async(
224→    content,
225→    title,
226→    userId,
227→    remixSourceJournalId = null,
228→    isRemix = false,
229→    promptId = null
230→) =>{
231→    if(!userId){
232→        console.error('userId is undefined');
233→        throw {status: 400, error: 'userId is undefined'};
234→    }
235→
236→    const trimmedTitle = typeof title === 'string' ? title.trim() : '';
237→
238→    if(!trimmedTitle){
239→        console.error('title is missing!');
240→        throw {status: 400, error: 'title is missing!'};
241→    }
242→
243→    const shouldSaveRemixMetadata = Boolean(
244→        remixSourceJournalId
245→        && typeof remixSourceJournalId === 'string'
246→        && remixSourceJournalId.trim()
247→    );
248→    const normalizedIsRemix = shouldSaveRemixMetadata || String(isRemix).toLowerCase() === 'true';
249→
250→    if(!content){
251→        console.error('content is missing for text post!');
252→        throw {status: 400, error: 'content is missing for text post'};
253→    }
254→
255→    const parseData = parseTextContentSafely(content);
256→    if(!parseData){
257→        console.error('error while parsing text content data');
258→        throw {status: 400, error: 'error while parsing text content data'};
259→    }
260→
261→    const embeddingBody = parseData.wholeText || '';
262→    const preview_text = parseData.slicedText || '';
263→    const thumbnail_url = parseData.firstImage?.src || null;
264→    const payload = {
265→        user_id: userId,
266→        title: trimmedTitle,
267→        post_type: POST_TYPE_TEXT,
268→        content: content,
269→        preview_text,
270→        thumbnail_url,
271→    };
272→
273→    const embeddingResult = await GenerateEmbeddings(trimmedTitle, embeddingBody);
274→
275→    if(!embeddingResult || !Array.isArray(embeddingResult) || embeddingResult.length === 0){
276→        console.error('error while generating embeddings on a post!');
277→        throw {status: 400, error: 'error while generating embeddings on a post!'};
278→    }
279→
280→    const insertPayload = {
281→        ...payload,
282→        embeddings: embeddingResult
283→    };
284→
285→    if(normalizedIsRemix){
286→        insertPayload.is_remix = true;
287→    }
288→    if(shouldSaveRemixMetadata){
289→        insertPayload.remix_source_journal_id = remixSourceJournalId.trim();
290→    }
291→    if(promptId){
292→        const parsedPromptId = parseInt(promptId, 10);
293→        if(!isNaN(parsedPromptId)){
294→            insertPayload.prompt_id = parsedPromptId;
295→        }
296→    }
297→
298→    let insertResult = await supabase
299→    .from('journals')
300→    .insert(insertPayload)
301→    .select('id')
302→    .single();
303→
304→    let error = insertResult.error;
305→
306→    if(error){
307→        const missingRemixColumns = error?.message?.includes('is_remix') || error?.message?.includes('remix_source_journal_id');
308→        if(missingRemixColumns){
309→            const fallbackPayload = {
310→                ...payload,
311→                embeddings: embeddingResult
312→            };
313→
314→            insertResult = await supabase
315→            .from('journals')
316→            .insert(fallbackPayload)
317→            .select('id')
318→            .single();
319→            error = insertResult.error;
320→        }
321→    }
322→
323→    if(error){
324→        console.error('supabase error while uploading content:',error.message);
325→        throw {status: 500, error: 'supabase error while uploading content'};
326→    }
327→
328→    const journalId = insertResult.data?.id;
329→
330→    // Non-fatal: send mention notifications
331→    if(journalId){
332→        try {
333→            const mentionedUserIds = extractMentionUserIds(content);
334→            const filtered = mentionedUserIds
