 98→export const deleteProfileMediaImageService = async(userId, bucket, path, url = "") => {
 99→    if(!userId){
100→        console.error("userId is undefined");
101→        throw {status: 400, error: "userId is undefined"};
102→    }
103→
104→    if(!bucket || typeof bucket !== "string"){
105→        console.error("bucket is undefined");
106→        throw {status: 400, error: "bucket is undefined"};
107→    }
108→
109→    if(!ALLOWED_MEDIA_BUCKETS.has(bucket)){
110→        console.error("bucket is not allowed");
111→        throw {status: 400, error: "bucket is not allowed"};
112→    }
113→
114→    if(!path || typeof path !== "string"){
115→        console.error("path is undefined");
116→        throw {status: 400, error: "path is undefined"};
117→    }
118→
119→    const normalizedPath = path.trim();
120→    const expectedPrefix = `user_id_${userId}/`;
121→    if(!normalizedPath.startsWith(expectedPrefix)){
122→        console.error("forbidden media path for user");
123→        throw {status: 403, error: "forbidden media path"};
124→    }
125→
126→    const siblingPaths = listVariantPathsForDeletion(normalizedPath)
127→        .filter((candidatePath) => candidatePath.startsWith(expectedPrefix));
128→
129→    const {error: removeError} = await supabase.storage
130→        .from(bucket)
131→        .remove([...new Set(siblingPaths.length > 0 ? siblingPaths : [normalizedPath])]);
132→
133→    if(removeError){
134→        console.error("supabase error while deleting profile media image:", removeError.message);
135→        throw {status: 500, error: "supabase error while deleting profile media image"};
136→    }
137→
138→    let clearedAvatar = false;
139→    let clearedBackground = false;
140→
141→    if(bucket === "avatars" || bucket === "background"){
142→        const {data: userData, error: userDataError} = await supabase
143→            .from("users")
144→            .select("id, image_url, background")
145→            .eq("id", userId)
146→            .maybeSingle();
147→
148→        if(userDataError){
149→            console.error("supabase error while loading user profile for media cleanup:", userDataError.message);
150→            throw {status: 500, error: "supabase error while loading user profile for media cleanup"};
151→        }
152→
153→        if(userData){
154→            const {data: publicUrlData} = supabase.storage
155→                .from(bucket)
156→                .getPublicUrl(normalizedPath);
157→
158→            const deletedPublicUrl = publicUrlData?.publicUrl || "";
159→            const updates = {};
160→
161→            if(bucket === "avatars"){
162→                const matchesAvatar = doesUrlMatchDeletedPath(userData?.image_url, bucket, normalizedPath, deletedPublicUrl, url);
163→                if(matchesAvatar){
164→                    updates.image_url = null;
165→                    clearedAvatar = true;
166→                }
167→            }
168→
169→            if(bucket === "background"){
170→                const backgroundImageUrl = extractBackgroundImageUrl(userData?.background);
171→                const matchesBackground = doesUrlMatchDeletedPath(backgroundImageUrl, bucket, normalizedPath, deletedPublicUrl, url);
172→                if(matchesBackground){
173→                    updates.background = null;
174→                    clearedBackground = true;
175→                }
176→            }
177→
178→            if(Object.keys(updates).length > 0){
179→                const {error: updateProfileError} = await supabase
180→                    .from("users")
181→                    .update(updates)
182→                    .eq("id", userId);
183→
184→                if(updateProfileError){
185→                    console.error("supabase error while clearing profile media references:", updateProfileError.message);
186→                    throw {status: 500, error: "supabase error while clearing profile media references"};
187→                }
188→            }
189→        }
190→    }
191→
192→    return {
193→        deleted: true,
194→        bucket: bucket,
195→        path: normalizedPath,
196→        clearedAvatar: clearedAvatar,
197→        clearedBackground: clearedBackground
198→    };
199→};
