471→        }
472→        hasLikedResult = hasLiked.data || [];
473→        hasBookMarkedResult = hasBookMarked.data || [];
474→    }
475→
476→    const userHasLikedSet = new Set(hasLikedResult.map((likes) => likes.journal_id));
477→    const userHasBookmarkedSet = new Set(hasBookMarkedResult.map((bookmarks) => bookmarks.journal_id));
478→
479→    const formatted = merged.map((notif) => decorateNotificationMedia({
480→        ...notif,
481→        hasLiked: notif.source === 'journal' ? userHasLikedSet.has(notif.journal_id) : false,
482→        hasBookMarked: notif.source === 'journal' ? userHasBookmarkedSet.has(notif.journal_id) : false
483→    }))
484→
485→    const hasMore = formatted.length > parsedLimit;
486→    const slicedData = hasMore ? formatted.slice(0, parsedLimit) : formatted;
487→
