 84→    .eq('id', userId)
 85→
 86→    const followerCountPromise = supabase
 87→    .from('follows')
 88→    .select('id', {count: 'exact', head: true})
 89→    .eq('following_id', userId)
 90→
 91→    const followingCountPromise = supabase
 92→    .from('follows')
 93→    .select('id', {count: 'exact', head: true})
 94→    .eq('follower_id', userId)
 95→
 96→    const [userDataResult, followerCountResult, followingCountResult] = await Promise.all([
 97→        userDataPromise, followerCountPromise, followingCountPromise
 98→    ])
 99→
100→    const {data: userData, error: errorUserData} = userDataResult;
101→    const {count: followerCount, error: errorFollowerCount} = followerCountResult;
102→    const {count: followingCount, error: errorFollowingCount} = followingCountResult;
103→
104→    if(errorUserData || errorFollowerCount || errorFollowingCount){
105→        console.error('supabase error while fetching user data:', errorUserData || errorFollowerCount || errorFollowingCount)
106→        throw {status: 400, message: 'supabase error while fetching user data'}
107→    }
108→    const data = {
109→        userData: Array.isArray(userData) ? userData.map((user) => decorateProfileUser(user)) : userData,
110→        followerCount: followerCount,
111→        followingCount: followingCount
112→    }
113→    return data;
114→}
