 66→        enabled: !!authData?.access_token,
 67→        staleTime: 1000 * 60 * 60,
 68→        cacheTime: 1000 * 60 * 60,
 69→    })
 70→    
 71→    //hook for realtime notifications
 72→    useEffect(() =>{
 73→        if(!userData) return;
 74→
 75→        const channel = supabase
 76→        .channel('notifications')
